import AppKit

/// The Cleaner brand logo, embedded as base64 so the menu-bar executable needs
/// no resource bundle. Used for the widget header and the menu-bar label icon.
enum CleanerLogo {
    // `nonisolated(unsafe)`: a decoded-once brand asset shared read-only across
    // isolation domains. NSImage isn't Sendable, but this instance is only
    // configured before return and never mutated afterward, so the escape hatch
    // is safe. Required by the stricter Swift 6 concurrency checking on CI.
    nonisolated(unsafe) static let image: NSImage = {
        let b64 = ""
        guard let data = Data(base64Encoded: b64), let img = NSImage(data: data) else {
            return NSImage(size: NSSize(width: 128, height: 128))
        }
        img.isTemplate = false
        return img
    }()
}
